     1→import { useState, useEffect, useCallback } from "react";
     2→
     3→const EXERCISES = {
     4→  A: [
     5→    { name: "Barbell Squat", sets: 3, targetReps: 8 },
     6→    { name: "Incline DB Bench", sets: 3, targetReps: 10 },
     7→    { name: "Barbell Row", sets: 3, targetReps: 8 },
     8→    { name: "Overhead Press", sets: 3, targetReps: 10 },
     9→    { name: "Face Pulls", sets: 3, targetReps: 15 },
    10→    { name: "Plank / Ab Wheel", sets: 3, targetReps: 1 },
    11→  ],
    12→  B: [
    13→    { name: "Romanian Deadlift", sets: 3, targetReps: 10 },
    14→    { name: "DB Chest Fly", sets: 3, targetReps: 12 },
    15→    { name: "Lat Pulldown", sets: 3, targetReps: 10 },
    16→    { name: "Lateral Raises", sets: 3, targetReps: 15 },
    17→    { name: "Bicep Curls", sets: 3, targetReps: 12 },
    18→    { name: "Tricep Pushdowns", sets: 3, targetReps: 12 },
    19→  ],
    20→  C: [
    21→    { name: "Bulgarian Split Squat", sets: 3, targetReps: 10 },
    22→    { name: "Push Ups (weighted/slow)", sets: 3, targetReps: 15 },
    23→    { name: "Cable Rows", sets: 3, targetReps: 12 },
    24→    { name: "Dips", sets: 3, targetReps: 10 },
    25→    { name: "Farmer Walks", sets: 3, targetReps: 1 },
    26→    { name: "Hanging Leg Raises", sets: 3, targetReps: 10 },
    27→  ],
    28→};
    29→
    30→const DAILY_HABITS = [
    31→  { id: "creatine", label: "5g Creatine", icon: "⚡" },
    32→  { id: "shake_am", label: "Morning Shake", icon: "🥤" },
    33→  { id: "protein_target", label: "140g+ Protein", icon: "🥩" },
    34→  { id: "calories", label: "2700+ Calories", icon: "🔥" },
    35→  { id: "water", label: "2.5L+ Water", icon: "💧" },
    36→];
    37→
    38→const todayKey = () => new Date().toISOString().slice(0, 10);
    39→
    40→const emptyWorkout = (type) =>
    41→  EXERCISES[type].map((ex) => ({
    42→    name: ex.name,
    43→    sets: Array.from({ length: ex.sets }, () => ({ weight: "", reps: "" })),
    44→  }));
    45→
    46→export default function FitnessTracker() {
    47→  const [tab, setTab] = useState("today");
    48→  const [habits, setHabits] = useState({});
    49→  const [bodyLog, setBodyLog] = useState([]);
    50→  const [workoutLog, setWorkoutLog] = useState([]);
    51→  const [weightInput, setWeightInput] = useState("");
    52→  const [bfInput, setBfInput] = useState("");
    53→  const [activeWorkout, setActiveWorkout] = useState(null);
    54→  const [workoutData, setWorkoutData] = useState(null);
    55→  const [loading, setLoading] = useState(true);
    56→  const [saving, setSaving] = useState(false);
    57→
    58→  // Load all data
    59→  useEffect(() => {
    60→    (async () => {
    61→      try {
    62→        const [hRes, bRes, wRes] = await Promise.all([
    63→          window.storage.get("habits").catch(() => null),
    64→          window.storage.get("bodylog").catch(() => null),
    65→          window.storage.get("workoutlog").catch(() => null),
    66→        ]);
    67→        if (hRes?.value) setHabits(JSON.parse(hRes.value));
    68→        if (bRes?.value) setBodyLog(JSON.parse(bRes.value));
    69→        if (wRes?.value) setWorkoutLog(JSON.parse(wRes.value));
    70→      } catch (e) {
    71→        console.error("Load error:", e);
    72→      }
    73→      setLoading(false);
    74→    })();
    75→  }, []);
    76→
    77→  const save = useCallback(
    78→    async (key, data) => {
    79→      setSaving(true);
    80→      try {
    81→        await window.storage.set(key, JSON.stringify(data));
    82→      } catch (e) {
    83→        console.error("Save error:", e);
    84→      }
    85→      setSaving(false);
    86→    },
    87→    []
    88→  );
    89→
    90→  const toggleHabit = async (id) => {
    91→    const today = todayKey();
    92→    const dayHabits = habits[today] || {};
    93→    const updated = {
    94→      ...habits,
    95→      [today]: { ...dayHabits, [id]: !dayHabits[id] },
    96→    };
    97→    setHabits(updated);
    98→    save("habits", updated);
    99→  };
   100→
   101→  const logBody = async () => {
   102→    if (!weightInput) return;
   103→    const entry = {
   104→      date: todayKey(),
   105→      weight: parseFloat(weightInput),
   106→      bf: bfInput ? parseFloat(bfInput) : null,
   107→    };
   108→    const updated = [...bodyLog.filter((b) => b.date !== todayKey()), entry].sort(
   109→      (a, b) => a.date.localeCompare(b.date)
   110→    );
   111→    setBodyLog(updated);
   112→    setWeightInput("");
   113→    setBfInput("");
   114→    save("bodylog", updated);
   115→  };
   116→
   117→  const startWorkout = (type) => {
   118→    setActiveWorkout(type);
   119→    setWorkoutData(emptyWorkout(type));
   120→  };
   121→
   122→  const updateSet = (exIdx, setIdx, field, val) => {
   123→    setWorkoutData((prev) => {
   124→      const next = JSON.parse(JSON.stringify(prev));
   125→      next[exIdx].sets[setIdx][field] = val;
   126→      return next;
   127→    });
   128→  };
   129→
   130→  const finishWorkout = async () => {
   131→    const entry = {
   132→      date: todayKey(),
   133→      type: activeWorkout,
   134→      exercises: workoutData,
   135→      ts: Date.now(),
   136→    };
   137→    const updated = [...workoutLog, entry];
   138→    setWorkoutLog(updated);
   139→    save("workoutlog", updated);
   140→    setActiveWorkout(null);
   141→    setWorkoutData(null);
   142→  };
   143→
   144→  const resetAll = async () => {
   145→    if (!confirm("Reset ALL data? This cannot be undone.")) return;
   146→    setHabits({});
   147→    setBodyLog([]);
   148→    setWorkoutLog([]);
   149→    await Promise.all([
   150→      window.storage.delete("habits").catch(() => {}),
   151→      window.storage.delete("bodylog").catch(() => {}),
   152→      window.storage.delete("workoutlog").catch(() => {}),
   153→    ]);
   154→  };
   155→
   156→  const todayHabits = habits[todayKey()] || {};
   157→  const habitsCompleted = DAILY_HABITS.filter((h) => todayHabits[h.id]).length;
   158→  const streak = (() => {
   159→    let count = 0;
   160→    const d = new Date();
   161→    while (true) {
   162→      const key = d.toISOString().slice(0, 10);
   163→      const dayH = habits[key] || {};
   164→      const done = DAILY_HABITS.filter((h) => dayH[h.id]).length;
   165→      if (done < 3 && count > 0) break;
   166→      if (done < 3 && count === 0) {
   167→        d.setDate(d.getDate() - 1);
   168→        continue;
   169→      }
   170→      count++;
   171→      d.setDate(d.getDate() - 1);
   172→    }
   173→    return count;
   174→  })();
   175→
   176→  const latestWeight = bodyLog.length ? bodyLog[bodyLog.length - 1].weight : 70.5;
   177→  const progressToGoal = Math.min(100, ((latestWeight - 70.5) / (75 - 70.5)) * 100);
   178→
   179→  if (loading) {
   180→    return (
   181→      <div style={styles.container}>
   182→        <div style={styles.loadingContainer}>
   183→          <div style={styles.spinner} />
   184→          <p style={{ color: "#94a3b8", marginTop: 16 }}>Loading your data...</p>
   185→        </div>
   186→      </div>
   187→    );
   188→  }
   189→
   190→  if (activeWorkout && workoutData) {
   191→    return (
   192→      <div style={styles.container}>
   193→        <div style={styles.workoutHeader}>
   194→          <button onClick={() => setActiveWorkout(null)} style={styles.backBtn}>
   195→            ← Back
   196→          </button>
   197→          <h2 style={styles.workoutTitle}>Full Body {activeWorkout}</h2>
   198→        </div>
   199→        <div style={styles.exerciseList}>
   200→          {workoutData.map((ex, exIdx) => {
   201→            const template = EXERCISES[activeWorkout][exIdx];
   202→            return (
   203→              <div key={exIdx} style={styles.exerciseCard}>
   204→                <div style={styles.exerciseName}>{ex.name}</div>
   205→                <div style={styles.targetText}>
   206→                  Target: {template.sets}×{template.targetReps}
   207→                  {template.targetReps === 1 ? " (hold/carry)" : ""}
   208→                </div>
   209→                <div style={styles.setsGrid}>
   210→                  {ex.sets.map((s, sIdx) => (
   211→                    <div key={sIdx} style={styles.setRow}>
   212→                      <span style={styles.setLabel}>Set {sIdx + 1}</span>
   213→                      <input
   214→                        type="number"
   215→                        placeholder="kg"
   216→                        value={s.weight}
   217→                        onChange={(e) =>
   218→                          updateSet(exIdx, sIdx, "weight", e.target.value)
   219→                        }
   220→                        style={styles.setInput}
   221→                      />
   222→                      <input
   223→                        type="number"
   224→                        placeholder="reps"
   225→                        value={s.reps}
   226→                        onChange={(e) =>
   227→                          updateSet(exIdx, sIdx, "reps", e.target.value)
   228→                        }
   229→                        style={styles.setInput}
   230→                      />
   231→                    </div>
   232→                  ))}
   233→                </div>
   234→              </div>
   235→            );
   236→          })}
   237→        </div>
   238→        <button onClick={finishWorkout} style={styles.finishBtn}>
   239→          ✓ Finish Workout
   240→        </button>
   241→      </div>
   242→    );
   243→  }
   244→
   245→  return (
   246→    <div style={styles.container}>
   247→      {/* Header */}
   248→      <div style={styles.header}>
   249→        <div>
   250→          <h1 style={styles.title}>IRON LOG</h1>
   251→          <p style={styles.subtitle}>70.5 → 75kg · 18% → 13% BF</p>
   252→        </div>
   253→        <div style={styles.streakBadge}>
   254→          <span style={styles.streakNum}>{streak}</span>
   255→          <span style={styles.streakLabel}>day streak</span>
   256→        </div>
   257→      </div>
   258→
   259→      {/* Tabs */}
   260→      <div style={styles.tabs}>
   261→        {["today", "log", "progress"].map((t) => (
   262→          <button
   263→            key={t}
   264→            onClick={() => setTab(t)}
   265→            style={{
   266→              ...styles.tab,
   267→              ...(tab === t ? styles.tabActive : {}),
   268→            }}
   269→          >
   270→            {t === "today" ? "Today" : t === "log" ? "Workouts" : "Progress"}
   271→          </button>
   272→        ))}
   273→      </div>
   274→
   275→      {/* Today Tab */}
   276→      {tab === "today" && (
   277→        <div style={styles.content}>
   278→          {/* Habits */}
   279→          <div style={styles.section}>
   280→            <div style={styles.sectionHeader}>
   281→              <h3 style={styles.sectionTitle}>Daily Habits</h3>
   282→              <span style={styles.habitCount}>
   283→                {habitsCompleted}/{DAILY_HABITS.length}
   284→              </span>
   285→            </div>
   286→            <div style={styles.habitBar}>
   287→              <div
   288→                style={{
   289→                  ...styles.habitBarFill,
   290→                  width: `${(habitsCompleted / DAILY_HABITS.length) * 100}%`,
   291→                }}
   292→              />
   293→            </div>
   294→            {DAILY_HABITS.map((h) => (
   295→              <button
   296→                key={h.id}
   297→                onClick={() => toggleHabit(h.id)}
   298→                style={{
   299→                  ...styles.habitRow,
   300→                  ...(todayHabits[h.id] ? styles.habitDone : {}),
   301→                }}
   302→              >
   303→                <span style={styles.habitIcon}>{h.icon}</span>
   304→                <span
   305→                  style={{
   306→                    ...styles.habitLabel,
   307→                    textDecoration: todayHabits[h.id]
   308→                      ? "line-through"
   309→                      : "none",
   310→                    opacity: todayHabits[h.id] ? 0.5 : 1,
   311→                  }}
   312→                >
   313→                  {h.label}
   314→                </span>
   315→                <span style={styles.habitCheck}>
   316→                  {todayHabits[h.id] ? "✓" : ""}
   317→                </span>
   318→              </button>
   319→            ))}
   320→          </div>
   321→
   322→          {/* Quick Workout Start */}
   323→          <div style={styles.section}>
   324→            <h3 style={styles.sectionTitle}>Start Workout</h3>
   325→            <div style={styles.workoutBtns}>
   326→              {["A", "B", "C"].map((type) => (
   327→                <button
   328→                  key={type}
   329→                  onClick={() => startWorkout(type)}
   330→                  style={styles.workoutTypeBtn}
   331→                >
   332→                  <span style={styles.workoutTypeLetter}>{type}</span>
   333→                  <span style={styles.workoutTypeLabel}>
   334→                    {type === "A"
   335→                      ? "Compound"
   336→                      : type === "B"
   337→                      ? "Hypertrophy"
   338→                      : "Hybrid"}
   339→                  </span>
   340→                </button>
   341→              ))}
   342→            </div>
   343→          </div>
   344→
   345→          {/* Body Log */}
   346→          <div style={styles.section}>
   347→            <h3 style={styles.sectionTitle}>Log Weight</h3>
   348→            <div style={styles.bodyInputRow}>
   349→              <input
   350→                type="number"
   351→                step="0.1"
   352→                placeholder="kg"
   353→                value={weightInput}
   354→                onChange={(e) => setWeightInput(e.target.value)}
   355→                style={styles.bodyInput}
   356→              />
   357→              <input
   358→                type="number"
   359→                step="0.5"
   360→                placeholder="BF%"
   361→                value={bfInput}
   362→                onChange={(e) => setBfInput(e.target.value)}
   363→                style={styles.bodyInput}
   364→              />
   365→              <button onClick={logBody} style={styles.logBtn}>
   366→                Log
   367→              </button>
   368→            </div>
   369→          </div>
   370→        </div>
   371→      )}
   372→
   373→      {/* Workouts Tab */}
   374→      {tab === "log" && (
   375→        <div style={styles.content}>
   376→          {workoutLog.length === 0 ? (
   377→            <p style={styles.emptyText}>
   378→              No workouts yet. Start your first one from the Today tab.
   379→            </p>
   380→          ) : (
   381→            [...workoutLog]
   382→              .reverse()
   383→              .slice(0, 20)
   384→              .map((w, i) => (
   385→                <div key={i} style={styles.workoutLogCard}>
   386→                  <div style={styles.logCardHeader}>
   387→                    <span style={styles.logCardType}>Full Body {w.type}</span>
   388→                    <span style={styles.logCardDate}>{w.date}</span>
   389→                  </div>
   390→                  {w.exercises.map((ex, j) => {
   391→                    const filledSets = ex.sets.filter(
   392→                      (s) => s.weight || s.reps
   393→                    );
   394→                    if (filledSets.length === 0) return null;
   395→                    return (
   396→                      <div key={j} style={styles.logExercise}>
   397→                        <span style={styles.logExName}>{ex.name}</span>
   398→                        <span style={styles.logExSets}>
   399→                          {filledSets
   400→                            .map((s) => `${s.weight || "?"}kg×${s.reps || "?"}`)
   401→                            .join("  ·  ")}
   402→                        </span>
   403→                      </div>
   404→                    );
   405→                  })}
   406→                </div>
   407→              ))
   408→          )}
   409→        </div>
   410→      )}
   411→
   412→      {/* Progress Tab */}
   413→      {tab === "progress" && (
   414→        <div style={styles.content}>
   415→          {/* Weight Progress */}
   416→          <div style={styles.section}>
   417→            <h3 style={styles.sectionTitle}>Weight Progress</h3>
   418→            <div style={styles.progressBar}>
   419→              <div
   420→                style={{
   421→                  ...styles.progressBarFill,
   422→                  width: `${Math.max(0, Math.min(100, progressToGoal))}%`,
   423→                }}
   424→              />
   425→            </div>
   426→            <div style={styles.progressLabels}>
   427→              <span>70.5kg (start)</span>
   428→              <span style={styles.currentWeight}>{latestWeight}kg</span>
   429→              <span>75kg (goal)</span>
   430→            </div>
   431→          </div>
   432→
   433→          {/* Body Log History */}
   434→          <div style={styles.section}>
   435→            <h3 style={styles.sectionTitle}>Body Log</h3>
   436→            {bodyLog.length === 0 ? (
   437→              <p style={styles.emptyText}>No entries yet.</p>
   438→            ) : (
   439→              <div style={styles.bodyLogGrid}>
   440→                <div style={styles.bodyLogHeader}>
   441→                  <span>Date</span>
   442→                  <span>Weight</span>
   443→                  <span>BF%</span>
   444→                </div>
   445→                {[...bodyLog]
   446→                  .reverse()
   447→                  .slice(0, 15)
   448→                  .map((b, i) => (
   449→                    <div key={i} style={styles.bodyLogRow}>
   450→                      <span style={styles.bodyLogDate}>{b.date}</span>
   451→                      <span style={styles.bodyLogVal}>{b.weight}kg</span>
   452→                      <span style={styles.bodyLogVal}>
   453→                        {b.bf ? `${b.bf}%` : "—"}
   454→                      </span>
   455→                    </div>
   456→                  ))}
   457→              </div>
   458→            )}
   459→          </div>
   460→
   461→          {/* Workout Stats */}
   462→          <div style={styles.section}>
   463→            <h3 style={styles.sectionTitle}>Workout Stats</h3>
   464→            <div style={styles.statsGrid}>
   465→              <div style={styles.statCard}>
   466→                <span style={styles.statNum}>{workoutLog.length}</span>
   467→                <span style={styles.statLabel}>Total Sessions</span>
   468→              </div>
   469→              <div style={styles.statCard}>
   470→                <span style={styles.statNum}>
   471→                  {workoutLog.filter((w) => w.date >= todayKey().slice(0, 7))
   472→                    .length}
   473→                </span>
   474→                <span style={styles.statLabel}>This Month</span>
   475→              </div>
   476→              <div style={styles.statCard}>
   477→                <span style={styles.statNum}>
   478→                  {(() => {
   479→                    const d = new Date();
   480→                    d.setDate(d.getDate() - 6);
   481→                    const weekAgo = d.toISOString().slice(0, 10);
   482→                    return workoutLog.filter((w) => w.date >= weekAgo).length;
   483→                  })()}
   484→                </span>
   485→                <span style={styles.statLabel}>This Week</span>
   486→              </div>
   487→            </div>
   488→          </div>
   489→
   490→          {/* Reset */}
   491→          <button onClick={resetAll} style={styles.resetBtn}>
   492→            Reset All Data
   493→          </button>
   494→        </div>
   495→      )}
   496→
   497→      {saving && <div style={styles.saveIndicator}>Saving...</div>}
   498→    </div>
   499→  );
   500→}
   501→
   502→const styles = {
   503→  container: {
   504→    fontFamily: "'JetBrains Mono', 'SF Mono', 'Fira Code', monospace",
   505→    background: "#0a0a0f",
   506→    color: "#e2e8f0",
   507→    minHeight: "100vh",
   508→    maxWidth: 480,
   509→    margin: "0 auto",
   510→    padding: "0 16px 32px",
   511→  },
   512→  loadingContainer: {
   513→    display: "flex",
   514→    flexDirection: "column",
   515→    alignItems: "center",
   516→    justifyContent: "center",
   517→    height: "60vh",
   518→  },
   519→  spinner: {
   520→    width: 32,
   521→    height: 32,
   522→    border: "3px solid #1e293b",
   523→    borderTop: "3px solid #f97316",
   524→    borderRadius: "50%",
   525→    animation: "spin 0.8s linear infinite",
   526→  },
   527→  header: {
   528→    display: "flex",
   529→    justifyContent: "space-between",
   530→    alignItems: "center",
   531→    padding: "24px 0 16px",
   532→    borderBottom: "1px solid #1e293b",
   533→  },
   534→  title: {
   535→    fontSize: 22,
   536→    fontWeight: 800,
   537→    letterSpacing: 4,
   538→    color: "#f97316",
   539→    margin: 0,
   540→  },
   541→  subtitle: {
   542→    fontSize: 11,
   543→    color: "#64748b",
   544→    marginTop: 4,
   545→    letterSpacing: 1,
   546→  },
   547→  streakBadge: {
   548→    display: "flex",
   549→    flexDirection: "column",
   550→    alignItems: "center",
   551→    background: "#1a1a2e",
   552→    borderRadius: 10,
   553→    padding: "8px 14px",
   554→    border: "1px solid #f9731630",
   555→  },
   556→  streakNum: {
   557→    fontSize: 24,
   558→    fontWeight: 800,
   559→    color: "#f97316",
   560→  },
   561→  streakLabel: {
   562→    fontSize: 9,
   563→    color: "#64748b",
   564→    textTransform: "uppercase",
   565→    letterSpacing: 1,
   566→  },
   567→  tabs: {
   568→    display: "flex",
   569→    gap: 4,
   570→    padding: "12px 0",
   571→    borderBottom: "1px solid #1e293b",
   572→  },
   573→  tab: {
   574→    flex: 1,
   575→    padding: "8px 0",
   576→    background: "transparent",
   577→    border: "1px solid #1e293b",
   578→    borderRadius: 6,
   579→    color: "#64748b",
   580→    fontSize: 12,
   581→    fontFamily: "inherit",
   582→    cursor: "pointer",
   583→    transition: "all 0.15s",
   584→  },
   585→  tabActive: {
   586→    background: "#f97316",
   587→    color: "#0a0a0f",
   588→    borderColor: "#f97316",
   589→    fontWeight: 700,
   590→  },
   591→  content: { paddingTop: 16 },
   592→  section: {
   593→    marginBottom: 24,
   594→  },
   595→  sectionHeader: {
   596→    display: "flex",
   597→    justifyContent: "space-between",
   598→    alignItems: "center",
   599→    marginBottom: 8,
   600→  },
   601→  sectionTitle: {
   602→    fontSize: 13,
   603→    fontWeight: 700,
