   252→   252→        <button class="day-btn" onclick="selectDay(this,4)">4</button>
   253→   253→        <button class="day-btn" onclick="selectDay(this,5)">5</button>
   254→   254→        <button class="day-btn" onclick="selectDay(this,6)">6</button>
   255→   255→      </div>
   256→   256→      <div id="split-preview" style="font-size:12px;color:#64748b;min-height:32px;margin-bottom:16px"></div>
   257→   257→      <button class="ob-btn" onclick="nextStep(5)">Continue →</button>
   258→   258→      <button class="ob-btn-ghost" onclick="prevStep(5)">← Back</button>
   259→   259→    </div>
   260→   260→
   261→   261→    <!-- Step 6: Review -->
   262→   262→    <div class="ob-step" id="step-6">
