   275→   275→    <div class="header-left">
   276→   276→      <div class="app-name">GYMBUDDY</div>
   277→   277→      <div class="app-greeting" id="app-greeting">Hey!</div>
   278→   278→      <div class="app-goal" id="app-goal"></div>
   279→   279→    </div>
   280→   280→    <div class="streak-badge">
   281→   281→      <span class="streak-num" id="streak-num">0</span>
   282→   282→      <span class="streak-label">day streak</span>
   283→   283→    </div>
   284→   284→  </div>
   285→   285→
   286→   286→  <div class="tabs">
   287→   287→    <button class="tab active" onclick="switchTab('today')">Today</button>
   288→   288→    <button class="tab" onclick="switchTab('log')">Log</button>
   289→   289→    <button class="tab" onclick="switchTab('paste')">AI Paste</button>
   290→   290→    <button class="tab" onclick="switchTab('progress')">Progress</button>
   291→   291→  </div>
   292→   292→
   293→   293→  <!-- Today -->
   294→   294→  <div class="panel active" id="panel-today">
   295→   295→    <div class="section">
   296→   296→      <div class="section-header">
   297→   297→        <div class="section-title" style="margin-bottom:0">Daily Habits</div>
   298→   298→        <span class="habit-count" id="habit-count">0/5</span>
   299→   299→      </div>
   300→   300→      <div class="habit-bar"><div class="habit-bar-fill" id="habit-bar-fill"></div></div>
   301→   301→      <div id="habits-list"></div>
   302→   302→    </div>
   303→   303→    <div class="section">
   304→   304→      <div class="section-title">Start Workout</div>
   305→   305→      <div class="workout-btns" id="workout-btns"></div>
   306→   306→    </div>
   307→   307→    <div class="section">
   308→   308→      <div class="section-title">Log Weight</div>
   309→   309→      <div class="body-input-row">
   310→   310→        <input class="body-input" type="number" step="0.1" placeholder="kg" id="weight-input"/>
   311→   311→        <input class="body-input" type="number" step="0.5" placeholder="BF%" id="bf-input"/>
   312→   312→        <button class="log-btn" onclick="logBody()">Log</button>
   313→   313→      </div>
   314→   314→    </div>
   315→   315→  </div>
   316→   316→
   317→   317→  <!-- Log -->
   318→   318→  <div class="panel" id="panel-log">
   319→   319→    <div id="workout-log-list"></div>
   320→   320→  </div>
   321→   321→
   322→   322→  <!-- AI Paste -->
   323→   323→  <div class="panel" id="panel-paste">
   324→   324→    <div class="section">
   325→   325→      <div class="section-title">Paste from Apple Notes</div>
   326→   326→      <textarea class="paste-area" id="paste-input" placeholder="Paste your notes here...
   327→   327→
   328→   328→Examples:
   329→   329→Workout A
   330→   330→Squat: 80kg x8, 82kg x8, 82kg x7
   331→   331→Bench: 70kg x10 x3
   332→   332→Weight: 71.5kg
   333→   333→Creatine ✓
   334→   334→Water 3L ✓
   335→   335→Protein 145g"></textarea>
   336→   336→      <button class="parse-btn" onclick="parsePaste()">Parse & Preview →</button>
   337→   337→      <div class="parse-hint">
   338→   338→        Understands formats like:<br/>
   339→   339→        <code>Squat: 80kg x8 x8</code> &nbsp;·&nbsp; <code>Bench 3x10 @70kg</code><br/>
   340→   340→        <code>Weight: 71.5</code> &nbsp;·&nbsp; <code>BF: 17%</code><br/>
   341→   341→        <code>Creatine ✓</code> &nbsp;·&nbsp; <code>protein 145g</code>
   342→   342→      </div>
   343→   343→    </div>
   344→   344→    <div class="parse-preview" id="parse-preview">
   345→   345→      <div class="parse-preview-title">Parsed — does this look right?</div>
   346→   346→      <div id="parse-rows"></div>
   347→   347→      <button class="parse-confirm" onclick="confirmPaste()">✓ Save to Log</button>
   348→   348→      <button class="parse-discard" onclick="discardPaste()">Discard</button>
   349→   349→    </div>
   350→   350→  </div>
   351→   351→
   352→   352→  <!-- Progress -->
   353→   353→  <div class="panel" id="panel-progress">
   354→   354→    <div class="section">
   355→   355→      <div class="section-title">Weight Progress</div>
   356→   356→      <div class="progress-bar"><div class="progress-bar-fill" id="progress-fill" style="width:0%"></div></div>
   357→   357→      <div class="progress-labels">
   358→   358→        <span id="prog-start">—</span>
   359→   359→        <span class="current-weight-label" id="prog-current">—</span>
   360→   360→        <span id="prog-goal">— (goal)</span>
   361→   361→      </div>
   362→   362→    </div>
   363→   363→    <div class="section">
   364→   364→      <div class="section-title">Body Log</div>
   365→   365→      <div id="body-log-list"></div>
   366→   366→    </div>
   367→   367→    <div class="section">
   368→   368→      <div class="section-title">Workout Stats</div>
   369→   369→      <div class="stats-grid">
   370→   370→        <div class="stat-card"><span class="stat-num" id="stat-total">0</span><span class="stat-label">Total</span></div>
   371→   371→        <div class="stat-card"><span class="stat-num" id="stat-month">0</span><span class="stat-label">Month</span></div>
   372→   372→        <div class="stat-card"><span class="stat-num" id="stat-week">0</span><span class="stat-label">Week</span></div>
   373→   373→      </div>
   374→   374→    </div>
   375→   375→    <button class="reset-btn" onclick="resetAll()">Reset All Data</button>
   376→   376→  </div>
   377→   377→</div>
   378→   378→
   379→   379→<!-- ── WORKOUT SESSION ──────────────────────────────────────────────────── -->
   380→   380→<div id="workout-screen">
   381→   381→  <div class="workout-header">
   382→   382→    <button class="back-btn" onclick="closeWorkout()">← Back</button>
   383→   383→    <div class="workout-session-title" id="workout-title">Workout</div>
   384→   384→  </div>
   385→   385→  <div id="exercise-list" style="padding-top:8px"></div>
   386→   386→  <button class="finish-btn" onclick="finishWorkout()">✓ Finish Workout</button>
   387→   387→</div>
   388→   388→
   389→   389→<!-- Toast -->
   390→   390→<div class="toast" id="toast">Saved!</div>
