1021→function buildAliases() {
1022→  if(!plan) return {};
1023→  const aliases={};
1024→  plan.workouts.forEach(w=>w.exercises.forEach(ex=>{
1025→    const nm=ex.name.toLowerCase();
1026→    const words=nm.split(/\s+/);
1027→    aliases[ex.name]=[nm,...words, words.join('')];
1028→    // common shorthands
1029→    if(nm.includes('squat')) aliases[ex.name].push('squat','squats');
1030→    if(nm.includes('bench')) aliases[ex.name].push('bench','bp');
1031→    if(nm.includes('row')) aliases[ex.name].push('row','rows');
1032→    if(nm.includes('deadlift')) aliases[ex.name].push('deadlift','dl','rdl');
1033→    if(nm.includes('romanian')) aliases[ex.name].push('rdl','romanian');
1034→    if(nm.includes('press')) aliases[ex.name].push('press','presses');
1035→    if(nm.includes('pulldown')) aliases[ex.name].push('pulldown','lat pull');
1036→    if(nm.includes('curl')) aliases[ex.name].push('curl','curls');
1037→    if(nm.includes('dip')) aliases[ex.name].push('dip','dips');
1038→    if(nm.includes('plank')) aliases[ex.name].push('plank');
1039→    if(nm.includes('lateral')) aliases[ex.name].push('lateral','laterals','side raises');
1040→    if(nm.includes('overhead')) aliases[ex.name].push('ohp','overhead','military');
1041→    if(nm.includes('pull-up')||nm.includes('pullup')) aliases[ex.name].push('pullup','pullups','pull up','pull-up','chinup','chin up');
1042→    if(nm.includes('hip thrust')) aliases[ex.name].push('hip thrust','hip thrusts','glute bridge');
1043→    if(nm.includes('leg press')) aliases[ex.name].push('leg press');
1044→    if(nm.includes('leg curl')) aliases[ex.name].push('leg curl','hamstring curl');
1045→    if(nm.includes('calf')) aliases[ex.name].push('calf','calves','calf raise');
1046→    if(nm.includes('face pull')) aliases[ex.name].push('face pull','face pulls');
1047→    if(nm.includes('farmer')) aliases[ex.name].push('farmer','farmer walk','farmers');
1048→    if(nm.includes('tricep')) aliases[ex.name].push('tricep','triceps','tris');
1049→    if(nm.includes('bicep')) aliases[ex.name].push('bicep','biceps','bis');
1050→    if(nm.includes('fly')||nm.includes('flye')) aliases[ex.name].push('fly','flye','flies');
1051→    if(nm.includes('split squat')) aliases[ex.name].push('split squat','bss','bulgarian');
1052→  }));
1053→  return aliases;
