1146→      water:/water\s*[\:✓\s]*(\d+(?:\.\d+)?)\s*l|(\d+(?:\.\d+)?)\s*l\+?\s*water/i,
1147→    };
1148→    let isHabit=false;
1149→    for(const h of HABITS){
1150→      const pat=habitPatterns[h.id];
1151→      if(pat&&pat.test(lower)){
1152→        const hasTick=lower.includes('✓')||lower.includes('done')||lower.includes('yes')||lower.includes('✅');
1153→        const hasNo=lower.includes('no ')||lower.includes('missed')||lower.includes('skip');
1154→        if(!hasNo){result.habits[h.id]=true; isHabit=true;}
1155→      }
1156→    }
1157→    if(isHabit) continue;
1158→
1159→    // Exercises — try to match exercise name in the line
