let pendingPaste = null;

// ── ONBOARDING STATE ─────────────────────────────────────────────────────
const ob = { name:'', sex:'male', height:'', weight:'', bf:'', goal:'', experience:'', days:0 };
const TOTAL_STEPS = 6;

function renderProgress(current) {
  const el = document.getElementById('ob-progress');
  el.innerHTML = Array.from({length:TOTAL_STEPS},(_,i)=>
    `<div class="ob-dot${i<current?' done':''}"></div>`).join('');
}

function selectChip(groupId, btn, val) {
  document.querySelectorAll(`#${groupId} .chip`).forEach(c=>c.classList.remove('selected'));
  btn.classList.add('selected');
  if(groupId==='sex-group') ob.sex=val;
  if(groupId==='goal-group') ob.goal=val;
  if(groupId==='exp-group') ob.experience=val;
}

function selectDay(btn, n) {
  document.querySelectorAll('.day-btn').forEach(b=>b.classList.remove('selected'));
  btn.classList.add('selected');
  ob.days=n;
  const p=PLANS[n];
  document.getElementById('split-preview').textContent = p ? `→ ${p.label}` : '';
}

function nextStep(current) {
  // Validation
  if(current===1) { ob.name=document.getElementById('ob-name').value.trim(); if(!ob.name){alert('Enter your name!');return;} }
  if(current===2) {
    ob.height=document.getElementById('ob-height').value;
    ob.weight=document.getElementById('ob-weight').value;
    ob.bf=document.getElementById('ob-bf').value;
    if(!ob.height||!ob.weight){alert('Height and weight required.');return;}
  }
  if(current===3&&!ob.goal){alert('Pick a goal.');return;}
  if(current===4&&!ob.experience){alert('Pick your experience level.');return;}
  if(current===5&&!ob.days){alert('Choose how many days per week.');return;}
  if(current===5) buildReview();
  goToStep(current+1);
}

function prevStep(current) { goToStep(current-1); }

function goToStep(n) {
  document.querySelectorAll('.ob-step').forEach((s,i)=>s.classList.toggle('active',i===n-1));
  renderProgress(n);
}

function buildReview() {
  const targets = calcTargets();
  const planData = generatePlan();
  const goalLabels={bulk:'Bulk — Build Muscle',cut:'Cut — Lose Fat',recomp:'Recomp',maintain:'Maintain'};
  const expLabels={beginner:'Beginner',intermediate:'Intermediate',advanced:'Advanced'};
  document.getElementById('ob-review-content').innerHTML=`
    <div class="ob-review-row"><span class="ob-review-key">Name</span><span class="ob-review-val">${ob.name}</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Stats</span><span class="ob-review-val">${ob.weight}kg · ${ob.height}cm${ob.bf?' · '+ob.bf+'% BF':''}</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Goal</span><span class="ob-review-val">${goalLabels[ob.goal]}</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Level</span><span class="ob-review-val">${expLabels[ob.experience]}</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Training</span><span class="ob-review-val">${ob.days} days/week</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Calories</span><span class="ob-review-val">${targets.calories} kcal/day</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Protein</span><span class="ob-review-val">${targets.protein}g/day</span></div>
    <div class="ob-review-row"><span class="ob-review-key">Split</span><span class="ob-review-val">${PLANS[ob.days].label}</span></div>
    <div class="ob-plan-preview">${planData.workouts.map(w=>`<div class="ob-plan-day"><strong>${w.key}</strong> — ${w.name} (${w.focus})</div>`).join('')}</div>
  `;
}

function calcTargets() {
  const w=parseFloat(ob.weight)||70, h=parseFloat(ob.height)||170;
  const bmr = ob.sex==='female' ? 10*w+6.25*h-5*25-161 : 10*w+6.25*h-5*25+5;
  const tdee = Math.round(bmr*1.55);
  let calories, protein;
  if(ob.goal==='bulk')     { calories=tdee+300; protein=Math.round(w*2.0); }
  else if(ob.goal==='cut') { calories=tdee-400; protein=Math.round(w*2.2); }
  else                     { calories=tdee;     protein=Math.round(w*1.8); }
  return { calories: Math.round(calories/50)*50, protein };
}

function generatePlan() {
  const template = PLANS[ob.days];
  const exp = ob.experience || 'intermediate';
  const workouts = template.workouts.map(w=>({
    key: w.key,
    name: w.name,
    focus: w.focus,
    exercises: (w[exp]||w.intermediate).map(e=>({...e})),
  }));
  return { workouts, splitLabel: template.label };
}

function startApp() {
  const targets = calcTargets();
  const planData = generatePlan();
  profile = {
    name: ob.name,
    sex: ob.sex,
    height: parseFloat(ob.height),
    weight: parseFloat(ob.weight),
    bf: ob.bf ? parseFloat(ob.bf) : null,
    goal: ob.goal,
    experience: ob.experience,
    days: ob.days,
    targets,
    startDate: todayKey(),
  };
  plan = planData;
  bodyLog = [{ date: todayKey(), weight: profile.weight, bf: profile.bf }];
  save('gb_profile', profile);

