// ── ONBOARDING STATE ─────────────────────────────────────────────────────
const ob = { name:'', sex:'male', height:'', weight:'', bf:'', goal:'', trainType:'', equipment:[], experience:'', days:0, apiKey:'' };

// Step order: 1=name,2=body,3=goal,4=trainType,5=equipment,6=aikey,7=experience,8=days,9=review
// Step 5 (equipment) is skipped when trainType==='running'
function getStepOrder() {
  const s=[1,2,3,4];
  if(ob.trainType!=='running') s.push(5);
  s.push(6,7,8,9);
  return s;
}

function renderProgress(current) {
  const order=getStepOrder();
  const idx=order.indexOf(current);
  const el=document.getElementById('ob-progress');
  el.innerHTML=Array.from({length:order.length},(_,i)=>
    `<div class="ob-dot${i<idx?' done':''}"></div>`).join('');
}

function selectChip(groupId, btn, val) {
  document.querySelectorAll(`#${groupId} .chip`).forEach(c=>c.classList.remove('selected'));
  btn.classList.add('selected');
  if(groupId==='sex-group') ob.sex=val;
  if(groupId==='goal-group') ob.goal=val;
  if(groupId==='exp-group') ob.experience=val;
  if(groupId==='train-group') ob.trainType=val;
}

function toggleEquip(btn, val) {
  if(val==='bodyweight') {
    ob.equipment=['bodyweight'];
    document.querySelectorAll('#equip-group .chip').forEach(c=>c.classList.remove('selected'));
    btn.classList.add('selected');
    return;
  }
  btn.classList.toggle('selected');
  const idx=ob.equipment.indexOf(val);
  if(idx>=0) ob.equipment.splice(idx,1);
  else { ob.equipment=ob.equipment.filter(e=>e!=='bodyweight'); ob.equipment.push(val);
    document.querySelectorAll('#equip-group .chip').forEach((c,i)=>{ if(i===7) c.classList.remove('selected'); }); }
}

function selectDay(btn, n) {
  document.querySelectorAll('.day-btn').forEach(b=>b.classList.remove('selected'));
  btn.classList.add('selected');
  ob.days=n;
  const planSet = ob.trainType==='running' ? RUN_PLANS : ob.trainType==='calisthenics'||ob.equipment.includes('bodyweight') ? CALI_PLANS : PLANS;
  const p=planSet[n]||PLANS[n];
  document.getElementById('split-preview').textContent = p ? `→ ${p.label}` : '';
}

function nextStep(current) {
  if(current===1) { ob.name=document.getElementById('ob-name').value.trim(); if(!ob.name){alert('Enter your name!');return;} }
  if(current===2) {
    ob.height=document.getElementById('ob-height').value;
    ob.weight=document.getElementById('ob-weight').value;
    ob.bf=document.getElementById('ob-bf').value;
    if(!ob.height||!ob.weight){alert('Height and weight required.');return;}
  }
  if(current===3&&!ob.goal){alert('Pick a goal.');return;}
  if(current===4&&!ob.trainType){alert('Pick a training style.');return;}
  if(current===7&&!ob.experience){alert('Pick your experience level.');return;}
  if(current===8&&!ob.days){alert('Choose how many days per week.');return;}
  if(current===8) buildReview();
  const order=getStepOrder();
  const idx=order.indexOf(current);
  if(idx<order.length-1) goToStep(order[idx+1]);
}

function prevStep(current) {
  const order=getStepOrder();
  const idx=order.indexOf(current);
  if(idx>0) goToStep(order[idx-1]);
}

function goToStep(n) {
  // n is logical step number; map to DOM index
  const allSteps=[1,2,3,4,5,6,7,8,9];
  document.querySelectorAll('.ob-step').forEach((s,i)=>s.classList.toggle('active',allSteps[i]===n));
  renderProgress(n);
}

// ── EQUIPMENT SUBSTITUTIONS ───────────────────────────────────────────────
const EQUIP_SUBS={
  'Barbell Squat':       {noBarbell:'Goblet Squat'},
  'Barbell Row':         {noBarbell:'DB Row'},
  'Deadlift':            {noBarbell:'DB Romanian Deadlift'},
  'Romanian Deadlift':   {noBarbell:'DB Romanian Deadlift'},
  'Overhead Press':      {noBarbell:'DB Shoulder Press'},
  'Bench Press':         {noBarbell:'DB Bench Press'},
  'Barbell Bench Press': {noBarbell:'DB Bench Press'},
  'Hip Thrust':          {noBarbell:'Glute Bridge'},
  'Lat Pulldown':        {noCables:'Band Pulldown / Inverted Row'},
  'Cable Row':           {noCables:'DB Row'},
  'Cable Fly':           {noCables:'DB Fly'},
  'Tricep Pushdowns':    {noCables:'Band Tricep Extension'},
  'Face Pulls':          {noCables:'Band Face Pulls'},
  'Straight-Arm Pulldown':{noCables:'Band Pulldown'},
  'Leg Press':           {noMachines:'Goblet Squat'},
  'Leg Curl':            {noMachines:'Nordic Curl'},
};

function applyEquipSubs(exercises) {
  const eq=ob.equipment;
  const hasBarbell=eq.includes('barbell');
  const hasCables=eq.includes('cables');
  const hasMachines=eq.includes('machines');
  if(eq.length===0||eq.includes('bodyweight')) return exercises; // no gym = calisthenics plan used
  return exercises.map(ex=>{
    const s=EQUIP_SUBS[ex.name];
    if(!s) return ex;
    let name=ex.name;
