function goToStep(n) {
  // n is logical step number; map to DOM index
  const allSteps=[1,2,3,4,5,6,7,8,9];
  document.querySelectorAll('.ob-step').forEach((s,i)=>s.classList.toggle('active',allSteps[i]===n));
  renderProgress(n);
}

